#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
class Solution {
public:
  void sort(vector<int>& nums) {
    if (nums.size() <= 1) return;
    int pivot = nums[0];
    int i = 1;
    for (int j = 1; j < nums.size(); j++) {
      if (nums[j] <= pivot) {
        swap(nums[i], nums[j]);
        i++;
      }
    }
    sort(nums.begin(), nums.begin() + i);
    sort(nums.begin() + i, nums.end());
  }
};
int main() {
  Solution sol;
  vector<int> nums = {5, 2, 9, 1, 7};
  sol.sort(nums);
  for (int num : nums) {
    cout << num << ' ';
  }
  return 0;
}
